 1→import React, { useState } from 'react';
 2→import { Search, ShieldCheck, TrendingUp, Sparkles } from 'lucide-react';
 3→
 4→interface AnalyzeProps {
 5→  onAnalyze: (url: string) => void;
 6→  isAnalyzing: boolean;
 7→}
 8→
 9→const Analyze: React.FC<AnalyzeProps> = ({ onAnalyze, isAnalyzing }) => {
10→  const [inputUrl, setInputUrl] = useState('');
11→
12→  const handleSubmit = (e: React.FormEvent) => {
13→    e.preventDefault();
14→    if (inputUrl && !isAnalyzing) {
15→      onAnalyze(inputUrl);
16→    }
17→  };
18→
19→  return (
20→    <div className="w-full px-4 min-h-[80vh] flex flex-col items-center justify-center animate-in fade-in duration-500">
21→      
22→      <div className="text-center mb-10 space-y-4">
23→        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.04] border border-white/[0.08] text-purple-400 text-sm font-medium">
24→          <Sparkles size={14} />
25→          <span>Audit AEO & GEO Instantané</span>
26→        </div>
27→        <h1 className="text-4xl md:text-5xl font-sans font-bold text-white">
28→          Analysez votre <span className="gradient-text">visibilité IA</span>
29→        </h1>
30→        <p className="text-xl text-gray-500 max-w-2xl mx-auto">
31→          Découvrez comment les moteurs de réponse perçoivent votre contenu et obtenez un plan d'action pour être cité.
32→        </p>
33→      </div>
34→
35→      <div className="w-full max-w-3xl relative z-10">
36→        <div className="absolute inset-0 bg-primary/20 blur-3xl rounded-full opacity-20 -z-10"></div>
37→        <form onSubmit={handleSubmit}>
38→          <div className="ninja-card p-8">
39→            <div className="flex items-center gap-3">
40→              <Search className="text-gray-500 shrink-0" size={24} />
41→              <input
42→                type="url"
43→                required
44→                placeholder="https://votre-site.com"
45→                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl focus:ring-1 focus:ring-purple-500/30 focus:border-purple-500/30 text-white placeholder-gray-500 text-lg px-4 py-4"
46→                value={inputUrl}
47→                onChange={(e) => setInputUrl(e.target.value)}
48→                autoFocus
49→              />
50→              <button
51→                type="submit"
52→                disabled={isAnalyzing}
53→                className={`btn-gradient px-8 py-4 shrink-0 transition-all transform hover:scale-105 ${isAnalyzing ? '!bg-gray-600 cursor-not-allowed opacity-60' : ''}`}
54→              >
55→                {isAnalyzing ? 'Analyse...' : 'Lancer l\'audit'}
56→              </button>
57→            </div>
58→          </div>
59→        </form>
60→        
61→        <div className="flex justify-center gap-8 mt-8 text-sm text-gray-500">
62→          <span className="flex items-center gap-2"><ShieldCheck size={16} className="text-purple-400"/> Analyse Sécurisée</span>
63→          <span className="flex items-center gap-2"><TrendingUp size={16} className="text-purple-400"/> +50 Critères GEO</span>
64→        </div>
65→      </div>
66→
67→    </div>
68→  );
69→};
70→
71→export default Analyze;

  1→import React from 'react';
