 35→
 36→  const tools = [
 37→    { id: 'smc-studio', label: t.generativeTools.smcStudio, icon: PenTool, color: 'text-purple-400', bg: 'bg-purple-500/10', desc: t.generativeTools.smcStudioDesc },
 38→    { id: 'content-writer', label: t.generativeTools.contentWriter, icon: Feather, color: 'text-violet-400', bg: 'bg-violet-500/10', desc: t.generativeTools.contentWriterDesc },
 39→    { id: 'reputation', label: t.generativeTools.reputation, icon: Shield, color: 'text-purple-400', bg: 'bg-purple-500/10', desc: t.generativeTools.reputationDesc },
 40→    { id: 'source-of-truth', label: t.generativeTools.sourceOfTruth, icon: FileText, color: 'text-purple-400', bg: 'bg-purple-500/10', desc: t.generativeTools.sourceOfTruthDesc },
 41→    { id: 'schema-org', label: t.generativeTools.schemaOrg, icon: Code, color: 'text-blue-400', bg: 'bg-blue-500/10', desc: t.generativeTools.schemaOrgDesc },
 42→    { id: 'robots-txt', label: t.generativeTools.robotsTxt, icon: FileCode, color: 'text-purple-300', bg: 'bg-purple-500/10', desc: t.generativeTools.robotsTxtDesc },
 43→    { id: 'bot-tracking', label: t.generativeTools.botTracking || 'Suivi Bots IA', icon: Bot, color: 'text-cyan-400', bg: 'bg-cyan-500/10', desc: t.generativeTools.botTrackingDesc || 'Activation & suivi des crawlers' },
 44→    { id: 'blog-optimizer', label: t.generativeTools.blogOptimizer || 'Blog Optimiser', icon: BookOpen, color: 'text-pink-400', bg: 'bg-pink-500/10', desc: t.generativeTools.blogOptimizerDesc || 'Architecture & rédaction blog AEO' },
 45→  ];
 46→
 47→  return (
 48→    <div className="w-full px-6 py-8 animate-in fade-in duration-500">
 49→
 50→      {/* Header style Dashboard Pro */}
 51→      <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-6">
 52→        <div className="flex items-center gap-4">
 53→          <h1 className="text-3xl font-bold text-white">{t.generativeTools.title.split(' ').slice(0, -1).join(' ')} <span className="gradient-text">{t.generativeTools.title.split(' ').slice(-1)}</span></h1>
 54→          <span className="bg-purple-500/10 text-purple-400 text-xs font-bold px-3 py-1 rounded-full border border-primary/20 flex items-center gap-1">
 55→            <Sparkles size={12} /> {t.generativeTools.suitePro}
 56→          </span>
 57→        </div>
 58→
 59→        <div className="flex items-center gap-4 w-full md:w-auto">
 60→          <div className="relative flex-1 md:flex-none">
 61→            <input
 62→              type="text"
 63→              placeholder={t.generativeTools.searchPlaceholder}
 64→              className="bg-[#111111] border border-white/[0.08] rounded-2xl py-2.5 pl-4 pr-10 text-sm text-gray-300 focus:outline-none focus:border-purple-500/50 w-full md:w-80 transition-all"
 65→            />
 66→            <Search size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" />
 67→          </div>
 68→        </div>
 69→      </div>
 70→
 71→      {/* Grid des Outils */}
 72→      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 mb-12">
 73→        {tools.map((tool) => (
 74→            <ToolCard
 75→                key={tool.id}
 76→                icon={tool.icon}
 77→                label={tool.label}
 78→                desc={tool.desc}
 79→                color={tool.color}
 80→                bg={tool.bg}
 81→                onClick={() => onNavigate(tool.id)}
 82→            />
 83→        ))}
 84→      </div>
 85→
 86→      {/* Section Explicative */}
 87→      <div className="ninja-card p-8">
 88→        <div className="flex items-center gap-3 mb-6">
 89→            <div className="p-2 bg-purple-500/10 rounded-full">
 90→                <AlertTriangle size={20} className="text-yellow-400" />
 91→            </div>
 92→            <h3 className="text-xl font-bold text-white">{t.generativeTools.whyUse}</h3>
 93→        </div>
 94→
 95→        <div className="grid md:grid-cols-3 gap-8">
 96→            <div className="space-y-3">
 97→                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.structuredContent}</h4>
