 332→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
 333→
 334→    // 1. Identifier la date de création (première analyse) de chaque domaine
 335→    const projectCreationDates = new Map<string, Date>();
 336→    
 337→    history.forEach(h => {
 338→        let hostname;
 339→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
 340→        
 341→        const analysisDate = new Date(h.timestamp);
 342→        
 343→        if (!projectCreationDates.has(hostname)) {
 344→            projectCreationDates.set(hostname, analysisDate);
 345→        } else {
 346→            // On garde la date la plus ancienne trouvée pour ce domaine
 347→            if (analysisDate < projectCreationDates.get(hostname)!) {
 348→                projectCreationDates.set(hostname, analysisDate);
 349→            }
 350→        }
 351→    });
 352→
 353→    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
 354→    let count = 0;
 355→    projectCreationDates.forEach((creationDate) => {
 356→        if (creationDate >= billingCycleStart) {
 357→            count++;
 358→        }
 359→    });
 360→    
 361→    return count;
